-- ----------------------------
-- Table structure for hustmonitorrecord
-- ----------------------------
DROP TABLE IF EXISTS `hustmonitorrecord`;
CREATE TABLE `hustmonitorrecord`  (
  `ip` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '主机IP地址',
  `timestamp` timestamp NOT NULL COMMENT '记录时间戳',
  `NetReceive` double NULL DEFAULT NULL COMMENT '网络接收速率',
  `NetSend` double NULL DEFAULT NULL COMMENT '网络发送速率',
  `MemTotal` int NULL DEFAULT NULL COMMENT '总内存大小',
  `MemFree` int NULL DEFAULT NULL COMMENT '空闲内存大小',
  `MemAvailable` int NULL DEFAULT NULL COMMENT '可用内存大小',
  `Buffers` double NULL DEFAULT NULL COMMENT '缓冲区大小',
  `Cached` double NULL DEFAULT NULL COMMENT '缓存大小',
  `TcpEstablished` int NULL DEFAULT NULL COMMENT 'TCP已建立连接数',
  `DiskTotalSize` double NULL DEFAULT NULL COMMENT '磁盘总大小',
  `DiskOccupancyUsage` double NULL DEFAULT NULL COMMENT '磁盘占用率',
  `CpuIdle` double NULL DEFAULT NULL COMMENT 'CPU空闲率',
  `Power` double NULL DEFAULT NULL COMMENT '功耗',
  `Temperature` double NULL DEFAULT NULL COMMENT '温度',
  `Iops` int NULL DEFAULT NULL COMMENT 'IOPS',
  `Type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '类型',
  `ReadRates` double NULL DEFAULT NULL COMMENT '读取速率',
  `WriteRates` double NULL DEFAULT NULL COMMENT '写入速率',
  `Utils` double NULL DEFAULT NULL COMMENT '利用率',
  PRIMARY KEY (`ip`, `timestamp`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

